import React from 'react'
import c from './navbar.module.scss'
import { Images } from '../../assets/images'
import { NavList } from '../../utils'

const Navbar = () => {
  return (
    <div className={c.navbar}>
      <div className={c.logo}>
        <img
          src={Images.logo}
          alt="logo"
        />
      </div>
      <ul className={c.list}>
        {
          NavList.map(({item, route, }))
        }
      </ul>
    </div>
  )
}

export default Navbar
